export type MajorKey = keyof typeof subjectsData;
export type SubjectKey<T extends MajorKey> = keyof (typeof subjectsData)[T];
export type UnitKey<T extends MajorKey, S extends SubjectKey<T>> = keyof (typeof subjectsData)[T][S];

export const getMajors = (): MajorKey[] => {
  return Object.keys(subjectsData).filter(key => key !== "การสื่อสารโทรคมนาคม") as MajorKey[];
};

export const getSubjects = (major: MajorKey): SubjectKey<typeof major>[] => {
  if (!subjectsData[major]) return [];
  return Object.keys(subjectsData[major]) as SubjectKey<typeof major>[];
};

export const getUnits = <T extends MajorKey, S extends SubjectKey<T>>(major: T, subject: S): UnitKey<T, S>[] => {
  if (!subjectsData[major] || !subjectsData[major][subject]) return [];
  const subjectData = subjectsData[major][subject];
  return Object.keys(subjectData) as UnitKey<T, S>[];
};

export const getTopics = <T extends MajorKey, S extends SubjectKey<T>, U extends UnitKey<T, S>>(major: T, subject: S, unit: U): string[] => {
  if (!subjectsData[major] || !subjectsData[major][subject] || !subjectsData[major][subject][unit]) {
    return [];
  }
  const unitData = subjectsData[major][subject][unit];
  if (Array.isArray(unitData)) {
    return unitData;
  }
  return [];
};
